--

/*!40000 ALTER TABLE `role` DISABLE KEYS */;
INSERT INTO `role` VALUES (1,1,'Super Admin','The ultimate authority in the system. The Super Admin possesses full, unrestricted access to configure the platform, manage all user accounts, and oversee every aspect of the system\'s data and functionality.',1,'2026-01-22','2026-01-22'),(2,2,'School Admin','The School Administrator serves as the primary manager of the institution\'s digital ecosystem, overseeing platform configuration, user access, and subscription services. This role is responsible for maintaining the operational integrity of the school\'s account, ensuring seamless access to tools and resources for faculty, staff, and students.',3,'2026-01-22','2026-01-22'),(3,3,'Principal','The Principal serves as the chief operational leader of the school, responsible for overseeing day-to-day academic and administrative functions while shaping the institution’s educational environment. This role goes beyond administration to directly impact teaching effectiveness, student development, and operational efficiency.',3,'2026-01-22','2026-01-22'),(4,3,'HOD','A Head of Department is a specialist leader and middle manager focused on a specific academic area (e.g., Math, Science, Industrial Arts). They are responsible for the quality, consistency, and innovation within their subject domain.',5,'2026-01-28','2026-01-28'),(5,3,'Assistant Teacher','An Assistant Teacher is a vital support professional within the classroom, working under the guidance of the HOD or Principal to facilitate student learning and well-being. This role focuses on implementing, assisting, and reinforcing the educational environment to ensure all students receive individualized attention and support.',6,'2026-01-28','2026-01-29'),(6,6,'Parent','The Parent role is a dedicated portal that provides real-time access to their child\'s academic and school life, transforming them from passive observers into active, informed participants in the educational process.',9,'2026-02-03','2026-02-03'),(7,4,'Student','The Student role is a personalized digital dashboard that centralizes a student\'s academic life, fostering independence, organization, and active engagement with their own learning process.',8,'2026-02-03','2026-02-03'),(8,5,'Support Staff','Support Staff are frontline operational specialists responsible for facilitating seamless technical assistance, user issue resolution, and day-to-day system support to maintain service excellence and client satisfaction.',7,'2026-01-23','2026-01-29'),(16,7,'Admin','Navuli Fiji Administrator',2,'2026-06-26','2026-06-26'),(17,3,'Head Master','The Head Master serves as the chief executive and strategic leader of the school, responsible for setting the overarching vision, academic direction, and cultural ethos of the institution. This role goes beyond operational management to directly shape the school’s long-term trajectory, ensuring the highest standards of teaching, character development, and institutional reputation.',3,'2026-07-16','2026-07-16'),(18,3,'Assistant Head Master','The Assistant Head Master serves as the senior operational deputy and principal advisor to the Head Master, responsible for translating strategic vision into daily institutional reality. This role goes beyond administrative support to directly drive teaching quality, student discipline, staff development, and the seamless functioning of school life.',4,'2026-07-16','2026-07-16'),(19,3,'Vice Principal','The Vice Principal serves as the senior executive deputy and chief operating officer of the school, responsible for driving operational excellence, academic accountability, and staff performance across the institution. This role goes beyond traditional deputising to actively shape school culture, enhance teaching effectiveness, and ensure the seamless integration of all school functions in support of the Principal\'s strategic vision.',4,'2026-07-16','2026-07-16'),(20,3,'Assistant Principal','The Assistant Principal serves as a senior instructional and pastoral leader within the school, responsible for driving teaching excellence, fostering student well-being, and building strong partnerships with parents and the wider community. This role goes beyond administrative support to directly influence classroom practice, student character development, and the overall school climate in alignment with the Principal\'s strategic vision.',4,'2026-07-16','2026-07-16'),(21,5,'School Counselor','The School Counselor serves as a dedicated student support professional, responsible for promoting the academic, social-emotional, and personal development of every student. This role goes beyond crisis intervention to proactively build resilience, foster positive mental health, and equip students with the life skills they need to navigate challenges and thrive both in and beyond the classroom.',4,'2026-07-16','2026-07-16');
/*!40000 ALTER TABLE `role` ENABLE KEYS */;

